RechargeUtil = {}

function RechargeUtil:doSumRechargeRewards(player, type, id, count)
    id = tonumber(id)
    if type == "Skin" then
        --皮肤
        PayStore:onBuySkin(player, id, false)
    elseif type == "FitnessEquip" then
        --健身器材
        GameFitnessEquip:onFitnessEquipBuy(player, id, false)
    elseif type == "Gene" then
        --基因
        GameGene:onGeneBuy(player, id, false)
    elseif type == "Skills" then
        --技能
        GameSkill:onSkillBuy(player, id, false)
    elseif type == "Coin" then
        --金币
        player.property:changeGold(count)
    else
        LogUtil.log("can not support reward type=" .. type .. ",id=" .. id)
    end
end